// Install: dotnet add package BenchmarkDotNet
[MemoryDiagnoser]
[RankColumn]
public class StringBenchmarks
{
    [Params(100, 1000, 10000)]
    public int N;

    [Benchmark(Baseline = true)]
    public void StringConcatN()
    {
        string s = "";
        for (int i = 0; i < N; i++) s += "x";
    }

    [Benchmark]
    public void StringBuilderN()
    {
        var sb = new System.Text.StringBuilder();
        for (int i = 0; i < N; i++) sb.Append('x');
        _ = sb.ToString();
    }

    [Benchmark]
    public void StringCreate()
    {
        _ = string.Create(N, N, (span, n) =>
        {
            for (int i = 0; i < n; i++) span[i] = 'x';
        });
    }
}

// Chạy: dotnet run -c Release
// Program.cs:
BenchmarkRunner.Run<StringBenchmarks>();
